/**
 * Event names each contract can emit, sorted for stable subscription lists.
 * Per-market OutcomeToken instances only emit the standard ERC20 events.
 */
export const postgradVenueEventNames = {
  BoundedPoolOrderManager: [
    "DeferredExecutionResolved",
    "DeferredExecutionStored",
    "HookRoleSet",
    "MaximumExecutionCountSet",
    "MinimumOrderAmountSet",
    "OrderCancelled",
    "OrderCreated",
    "OrderFilled",
    "OrderPartiallyFilled",
    "OrderRequeued",
    "OwnershipTransferred",
    "PoolWhitelistSet",
    "ResolverRoleSet",
  ],
  BoundedPredictionHook: ["AfterSwapTickObserved", "BeforeSwapTickObserved"],
  CompleteSetBinaryMarket: [
    "CancelledRedeemed",
    "CompleteSetsMerged",
    "CompleteSetsMinted",
    "DisputeBondForfeited",
    "DisputeBondPosted",
    "DisputeBondRefunded",
    "MarketCancelled",
    "MarketResolved",
    "OwnershipTransferred",
    "Redeemed",
    "ResolutionDisputed",
    "ResolutionProposed",
    "RetainedCollateralFunded",
    "RetainedSideMinted",
  ],
  CompleteSetPostgradAdapter: [
    "DisputeConfigUpdated",
    "OwnershipTransferred",
    "PostgradMarketPrepared",
    "RetainedOutcomeDistributed",
  ],
  MinimalV4SwapRouter: [],
  OutcomeToken: ["Approval", "Transfer"],
  PoolTickBounds: ["OwnershipTransferred", "PoolTickBoundsSet"],
} as const satisfies Record<PostgradVenueContractName, readonly string[]>;
export type PostgradVenueEventName =
  (typeof postgradVenueEventNames)[PostgradVenueContractName][number];

/** Singleton deployment entries for one network, keyed by manifest key. */
export type PostgradVenueNetworkDeployment = {
  readonly chainId: number;
  readonly contracts: Partial<Record<PostgradVenueSingletonKey, ProtocolContractDeployment>>;
};

export type PostgradVenueDeployments = Record<ProtocolNetworkId, PostgradVenueNetworkDeployment>;

/**
 * Singleton postgrad venue deployments promoted into
 * deployments/protocol.json. Networks without promoted entries stay as typed
 * placeholders; run-scoped addresses live in the (gitignored) venue-stack and
 * postgrad manifests instead.
 */
export const postgradVenueDeployments = {
  local: {
    chainId: 31337,
    contracts: {},
  },
  arcTestnet: {
    chainId: 5042002,
    contracts: {},
  },
} as const satisfies PostgradVenueDeployments;

